{
}

Method.Source:
/// <summary>
/// This method finds a particular record in TERMONumber Table 
/// </summary>
/// <param name = "termoNumber">ETGTERMONumber termoNumber</param>
/// <param name = "_forUpdate">boolean _forUpdate</param>
/// <returns>ETGTERMONumberTable</returns>
    static ETGTERMONumberTable findFromTermoNumber(ETGTERMONumber termoNumber, boolean _forUpdate = false)
{
    ETGTERMONumberTable termoNumberTable;

    termoNumberTable.selectForUpdate(_forUpdate);

    select firstonly termoNumberTable
        where termoNumberTable.TERMONumber == termoNumber;

    return termoNumberTable;
}

/// <summary>
/// This method changes TERMO number status to Close when remaining TERMO value become 0
/// </summary>
/// <returns></returns>
public display ETGTERMONumberStatus changeStatus()
{
    if(this.RemainingTermoValueReal == 0)
    {
        this.TERMONumberStatus = ETGTERMONumberStatus::Exhausted;
    }
    return this.TERMONumberStatus;
}

/// <summary>
/// This method is lookup for filtering TERMO Details with Open Status and type Import.
/// </summary>
/// <param name = "SalesParmTable_ETGTERMONumber">Form String Control SalesParmTable_ETGTERMONumber</param>
/// <param name = "importExportFilter">Boolean value for ETGImportOrExport importExportFilter passed from </param>
public static void lookupTERMONumberTable(FormStringControl SalesParmTable_ETGTERMONumber, ETGImportOrExport importExportFilter) 
{

    SysTableLookup        sysTableLookup;
    QueryBuildDataSource  queryBuildDataSource;
    QueryBuildRange       queryBuildRangeImportExport;
    QueryBuildRange       queryBuildRangeOpenCloseRange;
    QueryBuildRange       queryBuildRangeTypeOfTermo;
    Query query = new Query();


    sysTableLookup = SysTableLookup::newParameters(tablenum(ETGTERMONumberTable), SalesParmTable_ETGTERMONumber);
    queryBuildDataSource = query.addDataSource(tablenum(ETGTERMONumberTable));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, TERMONumber));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, TermoValueReal));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, RemainingTermoValueReal));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, ImportOrExport));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, BankName));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, PerformaInvoice));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, TypeOfTERMO));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, MotherTERMOReference));
    queryBuildRangeImportExport = queryBuildDataSource.addRange(fieldNum(ETGTERMONumberTable, ImportOrExport));


    if(importExportFilter == ETGImportOrExport::Export)
    {
        queryBuildRangeImportExport.value(SysQuery::value(ETGImportOrExport::Export));
    }
    if(importExportFilter == ETGImportOrExport::Import)
    {
        queryBuildRangeImportExport.value(SysQuery::value(ETGImportOrExport::Import));
    }
    queryBuildRangeImportExport.status(RangeStatus::Hidden);

    queryBuildRangeTypeOfTermo = queryBuildDataSource.addRange(fieldNum(ETGTERMONumberTable,TypeOfTERMO));
    queryBuildRangeTypeOfTermo.value(SysQuery::valueNot(ETGTypeOfTERMO::Mother));
    queryBuildRangeTypeOfTermo.status(RangeStatus::Hidden);

    queryBuildRangeOpenCloseRange = queryBuildDataSource.addRange(fieldNum(ETGTERMONumberTable, TERMONumberStatus));
    queryBuildRangeOpenCloseRange.value(SysQuery::value(ETGTERMONumberStatus::Open));
    queryBuildRangeOpenCloseRange.status(RangeStatus::Hidden);

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup(); 
}

public static void lookupTERMOByStatusOpen(FormStringControl formControl, ETGImportOrExport importExportFilter)
{

    SysTableLookup        sysTableLookup;
    QueryBuildDataSource  queryBuildDataSource;
    QueryBuildRange       queryBuildRangeImportExport;
    QueryBuildRange       queryBuildRangeOpenCloseRange;
    QueryBuildRange       queryBuildRangeTypeOfTermo;
    Query query = new Query();


    sysTableLookup = SysTableLookup::newParameters(tablenum(ETGTERMONumberTable), formControl);
    queryBuildDataSource = query.addDataSource(tablenum(ETGTERMONumberTable));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, TERMONumber));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, TermoValueReal));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, RemainingTermoValueReal));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, ImportOrExport));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, BankName));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, PerformaInvoice));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, TypeOfTERMO));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, MotherTERMOReference));
    queryBuildRangeImportExport = queryBuildDataSource.addRange(fieldNum(ETGTERMONumberTable, ImportOrExport));


    if(importExportFilter == ETGImportOrExport::Export)
    {
        queryBuildRangeImportExport.value(SysQuery::value(ETGImportOrExport::Export));
    }
    if(importExportFilter == ETGImportOrExport::Import)
    {
        queryBuildRangeImportExport.value(SysQuery::value(ETGImportOrExport::Import));
    }
    queryBuildRangeImportExport.status(RangeStatus::Hidden);

    queryBuildRangeOpenCloseRange = queryBuildDataSource.addRange(fieldNum(ETGTERMONumberTable, TERMONumberStatus));
    queryBuildRangeOpenCloseRange.value(SysQuery::value(ETGTERMONumberStatus::Canceled));
    queryBuildRangeOpenCloseRange.status(RangeStatus::Hidden);

    queryBuildRangeOpenCloseRange = queryBuildDataSource.addRange(fieldNum(ETGTERMONumberTable, TERMONumberStatus));
    queryBuildRangeOpenCloseRange.value(SysQuery::valueNot(ETGTERMONumberStatus::Close));
    queryBuildRangeOpenCloseRange.status(RangeStatus::Hidden);

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

/// <summary>
/// This method is Lookup for getting Mother TERMO Numbers with Open Status and export
/// </summary>
/// <param name = "formStringControl">FormStringControl formStringControl</param>
/// <param name = "termoTypeFilter">ETGTypeOfTERMO termoTypeFilter</param>
/// <param name = "importOrExport">ETGImportOrExport importOrExport</param>
public static void lookupMotherTermoNumber(FormStringControl formStringControl, 
    ETGTypeOfTERMO termoTypeFilter,
    ETGImportOrExport importOrExport)
{
    SysTableLookup        sysTableLookup;
    QueryBuildDataSource  queryBuildDataSource;
    QueryBuildRange       queryBuildRangeTypeOfTermo, queryBuildRangeImportExport, queryBuildRangeOpenCloseRange;
    Query                 query = new Query();

    sysTableLookup = SysTableLookup::newParameters(tablenum(ETGTERMONumberTable), formStringControl);
    queryBuildDataSource = query.addDataSource(tablenum(ETGTERMONumberTable));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, TERMONumber));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, TermoValueReal));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, RemainingTermoValueReal));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, BankName));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, PerformaInvoice));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, TypeOfTERMO));
    sysTableLookup.addLookupField(fieldNum(ETGTERMONumberTable, ImportOrExport));

    queryBuildRangeTypeOfTermo = queryBuildDataSource.addRange(fieldNum(ETGTERMONumberTable,TypeOfTERMO));
    queryBuildRangeTypeOfTermo.value(SysQuery::value(ETGTypeOfTERMO::Mother));
    queryBuildRangeTypeOfTermo.status(RangeStatus::Hidden);

    queryBuildRangeOpenCloseRange = queryBuildDataSource.addRange(fieldNum(ETGTERMONumberTable, TERMONumberStatus));
    queryBuildRangeOpenCloseRange.value(SysQuery::value(ETGTERMONumberStatus::Open));
    queryBuildRangeOpenCloseRange.status(RangeStatus::Hidden);

    queryBuildRangeImportExport = queryBuildDataSource.addRange(fieldNum(ETGTERMONumberTable, ImportOrExport));
    queryBuildRangeImportExport.value(SysQuery::value(importOrExport));
    queryBuildRangeImportExport.status(RangeStatus::Hidden);

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

/// <summary>
/// This method auto populates Remaining TERMO value when TERMO Value is entered and makes Exposrt if Type of TERMO is mother or child
/// </summary>
/// <param name = "_fieldId"></param>
public void modifiedField(FieldId _fieldId)
{
    super(_fieldId);

    switch (_fieldId)
    {
        case fieldNum(ETGTERMONumberTable, TermoValueReal):
            this.RemainingTermoValueReal       = this.TermoValueReal;
            this.RemainingClosedTERMOValueReal = this.TermoValueReal;
            break;
    }
}

/// <summary>
/// Overrides validateWrite method for TERMO Number Master fields validations
/// </summary>
/// <returns>boolean</returns>
public boolean validateWrite()
{
    boolean ret = super();
    ETGTERMONumberTable termoNumberTableMother;
    TransDate todayDate = DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone());

    if(this.TypeOfTERMO == ETGTypeOfTERMO::Child)
    {
        termoNumberTableMother = ETGTERMONumberTable::findFromTermoNumber(this.MotherTERMOReference, true);
        if(this.TermoValueReal > termoNumberTableMother.RemainingTermoValueReal && this.TERMONumberStatus == ETGTERMONumberStatus::Open)
        {
            if(TermoNumberTableMother.RemainingTermoValueReal == 0)
            {
                ret = checkFailed(strFmt("@ETG_New:ChildTERMOValidationRemainingValue0",  this.MotherTERMOReference));
            }
            else
            {
                ret = checkFailed(strFmt("@ETG_New:ChildTERMOValidationRemainingValue",  termoNumberTableMother.RemainingTermoValueReal, this.MotherTERMOReference));
            }
        }
        if(this.IssueDate && (this.IssueDate < termoNumberTableMother.IssueDate))
        {
            ret = checkFailed(strFmt("@ETG_New:ChildTERMOValidationIssueDate", this.IssueDate, termoNumberTableMother.IssueDate, this.TERMONumber));
        }
        if(this.DateOfSubmissionOrignalDoc && (this.DateOfSubmissionOrignalDoc < this.IssueDate))
        {
            ret = checkFailed(strFmt("@ETG_New:ChildTERMOValidationDateOfSubmissionOriginalDoc", this.DateOfSubmissionOrignalDoc, termoNumberTableMother.IssueDate, this.TERMONumber));
        }
        if(this.CustomsDeclarationDate && (this.CustomsDeclarationDate < termoNumberTableMother.IssueDate))
        {
            ret = checkFailed(strFmt("@ETG_New:ChildTERMOValidationCustomDeclarationDate", this.CustomsDeclarationDate, termoNumberTableMother.IssueDate, this.TERMONumber));
        }
        if(this.ImportOrExport != termoNumberTableMother.ImportOrExport)
        {
            ret = checkFailed(strFmt("@ETG_New:ChildTERMOValidationImportOrExport", termoNumberTableMother.ImportOrExport, this.TERMONumber));

        }
    }
    if(this.IssueDate)
    {
        if(this.StartDate && (this.IssueDate > this.StartDate))
        {
            ret = checkFailed(strFmt("@ETG_New:TERMONumberValidationStartDate", this.StartDate, this.IssueDate, this.TERMONumber));
        }

        if(this.IssueDate > todayDate)
        {
            ret = checkFailed(strFmt("@ETG_New:TERMONumberValidationIssueDate", this.IssueDate, todayDate, this.TERMONumber));
        }
    }

    if( this.DateOfSubmissionOrignalDoc)
    {
        if(this.ClosedDate && this.DateOfSubmissionOrignalDoc < this.ClosedDate)
        {
            ret = checkFailed(strFmt("@ETG_New:TERMONumberValidationDateOfSubmissionOfOriginalDoc", this.DateOfSubmissionOrignalDoc, this.ClosedDate, this.TERMONumber));
        }
    }
    if(this.DateOfOrignalDocReturrnReceived)
    {
        if( this.DateOfSubmissionOrignalDoc && (this.DateOfOrignalDocReturrnReceived < this.DateOfSubmissionOrignalDoc))
        {
            ret = checkFailed(strFmt("@ETG_New:TERMONumberValidationDateOfOriginalDocReturnReceived", this.DateOfOrignalDocReturrnReceived, this.DateOfSubmissionOrignalDoc, this.TERMONumber));
        }
        if(this.ClosedDate && this.DateOfOrignalDocReturrnReceived < this.ClosedDate)
        {
            ret = checkFailed(strFmt("@ETG_New:TERMONumberValidationDateOfOriginalDocumentReturnReceived", this.DateOfOrignalDocReturrnReceived, this.ClosedDate, this.TERMONumber));
        }
    }
    if(this.CustomsDeclarationEndDate)
    {
        if(this.CustomsDeclarationDate && (this.CustomsDeclarationEndDate < this.CustomsDeclarationDate))
        {
            ret = checkFailed(strFmt("@ETG_New:TERMONumberCustomDecEndDateError", this.CustomsDeclarationEndDate, this.CustomsDeclarationDate, this.TERMONumber));
        }
    }

    return ret;
}

/// <summary>
///
/// </summary>
public static void lookupCustomerName(FormStringControl _formControl)
{
    SysTableLookup sysTableLookup;
    Query query;
    QueryBuildDataSource qbds;

    sysTableLookup = SysTableLookup::newParameters(tableNum(CustTable), _formControl);

    query = new Query();
    qbds = query.addDataSource(tableNum(CustTable));

    sysTableLookup.addLookupField(fieldNum(CustTable, AccountNum));
    sysTableLookup.addLookupMethod(tableMethodStr(CustTable, Name));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

